B.O5=s(["SiE \u2014 Self-improvement Ecosystem \u2014 \u043d\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u044d\u0442\u043e \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u043e\u043d\u043d\u0430\u044f \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u043b\u0438\u0447\u043d\u043e\u0433\u043e \u0440\u043e\u0441\u0442\u0430. \u041a\u0430\u0436\u0434\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0437\u0434\u0435\u0441\u044c \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432\u043a\u043b\u0430\u0434\u043e\u043c \u0432 \u0434\u043e\u043b\u0433\u043e\u0441\u0440\u043e\u0447\u043d\u0443\u044e \u0430\u0440\u0445\u0438\u0442\u0435\u043a\u0442\u0443\u0440\u0443 \u0442\u0432\u043e\u0435\u0439 \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u0438.","\u041c\u044b \u0432\u0435\u0440\u0438\u043c \u0432 \u043d\u0430\u0443\u043a\u0443, \u0430 \u043d\u0435 \u0432 \u043c\u043e\u0442\u0438\u0432\u0430\u0446\u0438\u044e. \u041c\u043e\u0442\u0438\u0432\u0430\u0446\u0438\u044f \u043d\u0435\u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0430 \u2014 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u0438 \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u044b \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u044b. \u041a\u0430\u0436\u0434\u044b\u0439 \u043c\u043e\u0434\u0443\u043b\u044c SiE \u043f\u043e\u0441\u0442\u0440\u043e\u0435\u043d \u043d\u0430 \u0432\u0435\u0440\u0438\u0444\u0438\u0446\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u043c\u0435\u0445\u0430\u043d\u0438\u043a\u0430\u0445: \u043d\u0435\u0439\u0440\u043e\u0431\u0438\u043e\u043b\u043e\u0433\u0438\u0438 \u0434\u044b\u0445\u0430\u043d\u0438\u044f, \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u0440\u0438\u0432\u044b\u0447\u0435\u043a \u0438 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043d\u0430\u0443\u043a\u0435 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u0438.","\u041e\u043f\u0435\u0440\u0430\u0442\u0438\u0432\u043d\u0438\u043a SiE \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0441\u0432\u043e\u0439 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441. XP \u2014 \u044d\u0442\u043e \u043d\u0435 \u0438\u0433\u0440\u043e\u0432\u0430\u044f \u043c\u0435\u0445\u0430\u043d\u0438\u043a\u0430, \u044d\u0442\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u043c\u0435\u0440\u0430 \u0432\u043b\u043e\u0436\u0435\u043d\u043d\u044b\u0445 \u0443\u0441\u0438\u043b\u0438\u0439. \u0423\u0440\u043e\u0432\u0435\u043d\u044c \u2014 \u044d\u0442\u043e \u0440\u0430\u043d\u0433 \u0432 \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u0438 \u0442\u0435\u0445, \u043a\u0442\u043e \u0432\u044b\u0431\u0440\u0430\u043b \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u044b\u0439 \u043f\u043e\u0434\u0445\u043e\u0434 \u043a \u0441\u0435\u0431\u0435.",'\u041a\u043e\u0440\u043f\u043e\u0440\u0430\u0442\u0438\u0432\u043d\u044b\u0439 \u0434\u0435\u0432\u0438\u0437: "\u0414\u0438\u0441\u0446\u0438\u043f\u043b\u0438\u043d\u0430 \u2014 \u044d\u0442\u043e \u0444\u043e\u0440\u043c\u0430 \u0443\u0432\u0430\u0436\u0435\u043d\u0438\u044f \u043a \u0441\u0432\u043e\u0435\u043c\u0443 \u0431\u0443\u0434\u0443\u0449\u0435\u043c\u0443 \u044f."'],t.s)
