B.a54=new A.vN("M-02","HABIT ARCHIVE","\u0410\u0440\u0445\u0438\u0432 \u043d\u0435\u0439\u0440\u043e\u043d\u043d\u044b\u0445 \u0441\u0432\u044f\u0437\u0435\u0439","\u041f\u0440\u0438\u0432\u044b\u0447\u043a\u0430 \u2014 \u044d\u0442\u043e \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435, \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0451\u043d\u043d\u043e\u0435 \u0432 \u0431\u0430\u0437\u0430\u043b\u044c\u043d\u044b\u0435 \u0433\u0430\u043d\u0433\u043b\u0438\u0438: \u043d\u0435\u0439\u0440\u043e\u043d\u043d\u0443\u044e \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0443, \u043e\u0442\u0432\u0435\u0447\u0430\u044e\u0449\u0443\u044e \u0437\u0430 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0446\u0438\u044e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041a\u043e\u0433\u0434\u0430 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0430 \u0441\u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0430, \u043e\u043d\u0430 \u043d\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0432\u043e\u043b\u0435\u0432\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432.\n\n\u041c\u0435\u0445\u0430\u043d\u0438\u043a\u0430 \u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f (\u043c\u043e\u0434\u0435\u043b\u044c \u0427. \u0414\u0430\u0445\u0438\u0433\u0433\u0430):\n\u2192 \u0422\u0440\u0438\u0433\u0433\u0435\u0440 \u2192 \u0420\u0443\u0442\u0438\u043d\u0430 \u2192 \u041d\u0430\u0433\u0440\u0430\u0434\u0430\n\n\u0414\u043b\u044f \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043d\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044f \u0432 \u0441\u0440\u0435\u0434\u043d\u0435\u043c 66 \u0434\u043d\u0435\u0439 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e\u0433\u043e \u0432\u044b\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u044f (\u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 Lally et al., UCL). \u041a\u043b\u044e\u0447\u0435\u0432\u043e\u0439 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c \u2014 \u0441\u0442\u0440\u0438\u043a: \u043d\u0435\u043f\u0440\u0435\u0440\u044b\u0432\u043d\u0430\u044f \u0441\u0435\u0440\u0438\u044f \u043e\u0442\u043c\u0435\u0442\u043e\u043a.\n\n\u0421\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044f SiE: \u043d\u0430\u0447\u0438\u043d\u0430\u0439 \u0441 \u043c\u0438\u043a\u0440\u043e-\u043f\u0440\u0438\u0432\u044b\u0447\u0435\u043a (2-\u043c\u0438\u043d\u0443\u0442\u043d\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e). \u041c\u0430\u043b\u044b\u0435 \u043f\u043e\u0431\u0435\u0434\u044b \u043d\u0430\u043a\u0430\u043f\u043b\u0438\u0432\u0430\u044e\u0442 \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043c\u043f\u0443\u043b\u044c\u0441. \u0421\u0438\u0441\u0442\u0435\u043c\u0430 \u0442\u0440\u0435\u043a\u0438\u043d\u0433\u0430 \u0438 \u043f\u0438\u043d\u044b \u0434\u043b\u044f \u043f\u0440\u0438\u043e\u0440\u0438\u0442\u0435\u0442\u043d\u044b\u0445 \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u043e\u0432 \u043f\u043e\u043c\u043e\u0433\u0430\u044e\u0442 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435\u043c.",null)
B.a53=new A.vN("M-03","FOCUS PROTOCOL","\u041f\u0440\u043e\u0442\u043e\u043a\u043e\u043b \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u044b","\u041c\u0435\u0442\u043e\u0434 \u041f\u043e\u043c\u043e\u0434\u043e\u0440\u043e (\u0424\u0440\u0430\u043d\u0447\u0435\u0441\u043a\u043e \u0427\u0438\u0440\u0438\u043b\u043b\u043e, 1980-\u0435) \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442 \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0301\u0435 \u0431\u043b\u043e\u043a\u0438 \u0434\u043b\u044f \u0437\u0430\u0449\u0438\u0442\u044b \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f \u0433\u043b\u0443\u0431\u043e\u043a\u043e\u0433\u043e \u043f\u043e\u0442\u043e\u043a\u0430 \u043e\u0442 \u043f\u0440\u0435\u0440\u044b\u0432\u0430\u043d\u0438\u0439.\n\n\u041d\u0435\u0439\u0440\u043e\u0431\u0438\u043e\u043b\u043e\u0433\u0438\u044f: \u0432 \u0442\u0435\u0447\u0435\u043d\u0438\u0435 25-\u043c\u0438\u043d\u0443\u0442\u043d\u043e\u0433\u043e \u0431\u043b\u043e\u043a\u0430 \u043c\u043e\u0437\u0433 \u0432\u0445\u043e\u0434\u0438\u0442 \u0432 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0439 \u0430\u043a\u0442\u0438\u0432\u0430\u0446\u0438\u0438 \u043f\u0440\u0435\u0444\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043a\u043e\u0440\u044b. \u041f\u0435\u0440\u0438\u043e\u0434\u044b \u043e\u0442\u0434\u044b\u0445\u0430 \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u044b \u0434\u043b\u044f \u043a\u043e\u043d\u0441\u043e\u043b\u0438\u0434\u0430\u0446\u0438\u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u0438 \u043f\u0440\u0435\u0434\u043e\u0442\u0432\u0440\u0430\u0449\u0435\u043d\u0438\u044f \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0438\u0441\u0442\u043e\u0449\u0435\u043d\u0438\u044f.\n\n\u041d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438 \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u0430 SiE:\n\u2192 \u0420\u0430\u0431\u043e\u0447\u0438\u0439 \u0431\u043b\u043e\u043a: 15\u201360 \u043c\u0438\u043d\u0443\u0442 (\u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e 25)\n\u2192 \u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u043e\u0442\u0434\u044b\u0445: 5\u201315 \u043c\u0438\u043d\u0443\u0442 (\u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e 5)\n\u2192 \u0414\u043b\u0438\u043d\u043d\u044b\u0439 \u043e\u0442\u0434\u044b\u0445: 15\u201330 \u043c\u0438\u043d\u0443\u0442 \u0447\u0435\u0440\u0435\u0437 \u043a\u0430\u0436\u0434\u044b\u0435 4 \u0441\u0435\u0441\u0441\u0438\u0438\n\n\u0418\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442: 4 \u0437\u0430\u0432\u0435\u0440\u0448\u0451\u043d\u043d\u044b\u0435 \u043f\u043e\u043c\u043e\u0434\u043e\u0440\u043e \u0432 \u0434\u0435\u043d\u044c \u043a\u043e\u0440\u0440\u0435\u043b\u0438\u0440\u0443\u044e\u0442 \u0441 2\xd7 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c\u044e \u043f\u043e \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u044e \u0441 \u043d\u0435\u043f\u0440\u0435\u0440\u044b\u0432\u043d\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u043e\u0439 \u0442\u043e\u0433\u043e \u0436\u0435 \u0441\u0443\u043c\u043c\u0430\u0440\u043d\u043e\u0433\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438.",null)
